"use strict";(self.webpackChunkspanish_app=self.webpackChunkspanish_app||[]).push([[2595],{2595:e=>{e.exports=JSON.parse('{"34":{"words":[{"spanish":"estimado/a","english":"dear"},{"spanish":"le escribo para","english":"I am writing to"},{"spanish":"quisiera comentar","english":"I would like to discuss"},{"spanish":"retomando el tema anterior","english":"returning to the previous topic"},{"spanish":"en resumen","english":"in summary"},{"spanish":"estamos dispuestos a","english":"we are willing to"},{"spanish":"propongo que","english":"I propose that"},{"spanish":"\xbfQu\xe9 le parece si...?","english":"what do you think if...?"},{"spanish":"llegar a un acuerdo","english":"to reach an agreement"},{"spanish":"ceder en algo","english":"to give ground on something"},{"spanish":"un punto medio","english":"a middle ground"},{"spanish":"el plazo de entrega","english":"the delivery deadline"},{"spanish":"la propuesta adjunta","english":"the attached proposal"},{"spanish":"la reuni\xf3n de seguimiento","english":"the follow-up meeting"},{"spanish":"la contrapropuesta","english":"the counterproposal"},{"spanish":"el presupuesto disponible","english":"the available budget"},{"spanish":"la carga de trabajo","english":"the workload"},{"spanish":"la aprobaci\xf3n final","english":"the final approval"},{"spanish":"la versi\xf3n revisada","english":"the revised version"},{"spanish":"la viabilidad del proyecto","english":"the project\'s viability"},{"spanish":"la parte interesada","english":"the stakeholder"},{"spanish":"el margen de maniobra","english":"the room for maneuver"},{"spanish":"la prioridad estrat\xe9gica","english":"the strategic priority"},{"spanish":"solicitar una pr\xf3rroga","english":"to request an extension"},{"spanish":"asumir la responsabilidad","english":"to take responsibility"},{"spanish":"dejar constancia","english":"to place on record"},{"spanish":"agradecer de antemano","english":"to thank in advance"},{"spanish":"quedo a la espera de su respuesta","english":"I look forward to your reply"},{"spanish":"atentamente","english":"sincerely"},{"spanish":"seg\xfan lo acordado","english":"as agreed"},{"spanish":"por motivos operativos","english":"for operational reasons"},{"spanish":"con el debido respeto","english":"with due respect"},{"spanish":"revisar los t\xe9rminos","english":"to review the terms"},{"spanish":"alcanzar un compromiso","english":"to reach a compromise"},{"spanish":"una soluci\xf3n escalonada","english":"a phased solution"},{"spanish":"una cl\xe1usula adicional","english":"an additional clause"},{"spanish":"el valor a\xf1adido","english":"the added value"},{"spanish":"el calendario propuesto","english":"the proposed timeline"},{"spanish":"una reuni\xf3n presencial","english":"an in-person meeting"},{"spanish":"una decisi\xf3n consensuada","english":"a consensus decision"},{"spanish":"la negociaci\xf3n interna","english":"the internal negotiation"},{"spanish":"la propuesta provisional","english":"the provisional proposal"}],"conversations":[{"id":1,"topic":"Negociar un plazo de entrega","dialog":[{"speaker":"Elena","spanish":"Quisiera comentar el calendario propuesto para el informe regional. Con el volumen actual de incidencias, llegar al viernes sin reducir calidad ser\xe1 dif\xedcil.","english":"I would like to discuss the proposed timeline for the regional report. With the current volume of issues, meeting Friday without reducing quality will be difficult."},{"speaker":"Ricardo","spanish":"Gracias por se\xf1alarlo. Estamos dispuestos a revisar el plazo, aunque la direcci\xf3n espera una versi\xf3n preliminar para presentarla el lunes.","english":"Thank you for pointing that out. We are willing to review the deadline, although leadership expects a preliminary version to present on Monday."},{"speaker":"Elena","spanish":"Propongo que entreguemos el an\xe1lisis cuantitativo el lunes y la secci\xf3n estrat\xe9gica el mi\xe9rcoles, de modo que el equipo no tenga que ceder en la verificaci\xf3n de datos.","english":"I propose that we deliver the quantitative analysis on Monday and the strategic section on Wednesday, so that the team does not have to compromise on data verification."},{"speaker":"Ricardo","spanish":"Es una opci\xf3n razonable. \xbfQu\xe9 le parece si incorporamos a Paula en la revisi\xf3n final para repartir la carga de trabajo y mantener el compromiso con la direcci\xf3n?","english":"That is a reasonable option. What do you think if we bring Paula into the final review to distribute the workload and keep our commitment to management?"},{"speaker":"Elena","spanish":"Me parece un buen punto medio, siempre que quede constancia de que la pr\xf3rroga parcial responde a motivos operativos y no a falta de planificaci\xf3n.","english":"That seems like a good middle ground to me, provided it is placed on record that the partial extension is due to operational reasons and not poor planning."},{"speaker":"Ricardo","spanish":"De acuerdo. En resumen, ajustamos el cronograma, reforzamos la revisi\xf3n y yo comunicar\xe9 la decisi\xf3n consensuada en la reuni\xf3n de seguimiento.","english":"Agreed. In summary, we will adjust the schedule, strengthen the review, and I will communicate the consensus decision in the follow-up meeting."}],"questions":[{"question":"\xbfPor qu\xe9 pide Elena un ajuste del calendario?","options":["Porque quiere posponer el proyecto sin motivo","Porque el equipo no ha empezado a trabajar","Porque con la carga actual ser\xeda dif\xedcil mantener la calidad hasta el viernes","Porque la direcci\xf3n cancel\xf3 la presentaci\xf3n del lunes"],"answer":"Porque con la carga actual ser\xeda dif\xedcil mantener la calidad hasta el viernes","answerIndex":2},{"question":"\xbfQu\xe9 aspecto desea proteger Elena con su propuesta?","options":["La verificaci\xf3n rigurosa de los datos","La presencia f\xedsica de todo el equipo","La reducci\xf3n permanente de tareas","La eliminaci\xf3n de la secci\xf3n estrat\xe9gica"],"answer":"La verificaci\xf3n rigurosa de los datos","answerIndex":0},{"question":"\xbfQui\xe9n se encargar\xe1 de comunicar el acuerdo final?","options":["Paula","Ricardo","Elena","La direcci\xf3n regional"],"answer":"Ricardo","answerIndex":1}]},{"id":2,"topic":"Negociaci\xf3n con un proveedor","dialog":[{"speaker":"Marta","spanish":"Retomando el tema anterior, su contrapropuesta mejora el soporte t\xe9cnico, pero el presupuesto disponible no nos permite aceptar el precio completo.","english":"Returning to the previous topic, your counterproposal improves technical support, but the available budget does not allow us to accept the full price."},{"speaker":"Sergio","spanish":"Lo entiendo. Estamos dispuestos a reducir la cuota inicial si el contrato se ampl\xeda a dieciocho meses, porque as\xed podemos distribuir mejor los costes.","english":"I understand. We are willing to reduce the initial fee if the contract is extended to eighteen months, because that lets us spread the costs better."},{"speaker":"Marta","spanish":"Agradezco la flexibilidad. No obstante, la aprobaci\xf3n final depende de finanzas, y prefieren compromisos m\xe1s cortos mientras se eval\xfaa la viabilidad del proyecto.","english":"I appreciate the flexibility. Nevertheless, final approval depends on finance, and they prefer shorter commitments while the project\'s viability is being assessed."},{"speaker":"Sergio","spanish":"En ese caso, \xbfqu\xe9 le parece si mantenemos doce meses y limitamos ciertas personalizaciones avanzadas a una fase posterior?","english":"In that case, what do you think if we keep twelve months and limit certain advanced customizations to a later phase?"},{"speaker":"Marta","spanish":"Esa soluci\xf3n escalonada podr\xeda funcionar, siempre que la propuesta adjunta especifique qu\xe9 servicios quedan incluidos desde el inicio.","english":"That phased solution could work, provided the attached proposal specifies which services are included from the start."},{"speaker":"Sergio","spanish":"Perfecto. Le enviar\xe9 una versi\xf3n revisada esta tarde y quedo a la espera de su respuesta para intentar llegar a un acuerdo ma\xf1ana.","english":"Perfect. I will send you a revised version this afternoon and I look forward to your reply so we can try to reach an agreement tomorrow."}],"questions":[{"question":"\xbfQu\xe9 impide a Marta aceptar el precio completo de inmediato?","options":["Que el soporte t\xe9cnico es insuficiente","Que el presupuesto disponible y finanzas limitan el compromiso","Que el proveedor retir\xf3 la oferta","Que el contrato exige una reuni\xf3n presencial obligatoria"],"answer":"Que el presupuesto disponible y finanzas limitan el compromiso","answerIndex":1},{"question":"\xbfQu\xe9 alternativa propone Sergio para acercar posiciones?","options":["Eliminar por completo el soporte t\xe9cnico","Mantener doce meses y posponer algunas personalizaciones","Aumentar el precio y reducir el contrato","Esperar seis meses antes de negociar"],"answer":"Mantener doce meses y posponer algunas personalizaciones","answerIndex":1},{"question":"\xbfQu\xe9 necesita Marta antes de dar una respuesta final?","options":["Una carta del director general","Una versi\xf3n revisada que detalle los servicios iniciales","Una auditor\xeda externa completa","Un descuento adicional del cincuenta por ciento"],"answer":"Una versi\xf3n revisada que detalle los servicios iniciales","answerIndex":1}]},{"id":3,"topic":"Solicitar trabajo h\xedbrido temporal","dialog":[{"speaker":"Paula","spanish":"Le escribo para solicitar un ajuste en mi modalidad de trabajo durante los pr\xf3ximos dos meses, ya que coordino el tratamiento de un familiar fuera de la ciudad.","english":"I am writing to request an adjustment to my work arrangement over the next two months, since I am coordinating a relative\'s treatment outside the city."},{"speaker":"Diego","spanish":"Gracias por explicarlo con claridad. Quisiera comentar qu\xe9 tareas requieren presencia f\xedsica y cu\xe1les podr\xedan gestionarse en remoto sin afectar al servicio.","english":"Thank you for explaining it clearly. I would like to discuss which tasks require physical presence and which could be handled remotely without affecting service."},{"speaker":"Paula","spanish":"Podr\xeda asistir en persona a las reuniones con clientes los martes y jueves; en cambio, los informes y la negociaci\xf3n interna se pueden resolver por videollamada.","english":"I could attend client meetings in person on Tuesdays and Thursdays; by contrast, reports and internal negotiation can be handled by video call."},{"speaker":"Diego","spanish":"Me parece viable, aunque necesitamos dejar un punto de contacto claro para el resto del equipo, sobre todo cuando surjan aprobaciones urgentes.","english":"That seems workable, although we need to establish a clear point of contact for the rest of the team, especially when urgent approvals arise."},{"speaker":"Paula","spanish":"Propongo que Laura asuma la validaci\xf3n presencial y que yo quede disponible por tel\xe9fono hasta las seis, con lo cual no se interrumpe el flujo de decisiones.","english":"I propose that Laura handle in-person validation and that I remain available by phone until six, which would prevent the decision flow from being interrupted."},{"speaker":"Diego","spanish":"De acuerdo. Redacte un plan breve con ese esquema y, si recursos humanos lo confirma, podremos formalizar un punto medio satisfactorio para todos.","english":"Agreed. Draft a brief plan with that outline and, if human resources confirms it, we will be able to formalize a middle ground that works for everyone."}],"questions":[{"question":"\xbfCu\xe1l es el motivo de la solicitud de Paula?","options":["Quiere mudarse definitivamente a otra empresa","Necesita coordinar una situaci\xf3n familiar fuera de la ciudad","Desea evitar todas las reuniones con clientes","Pretende reducir su jornada laboral a la mitad"],"answer":"Necesita coordinar una situaci\xf3n familiar fuera de la ciudad","answerIndex":1},{"question":"\xbfQu\xe9 tareas propone Paula hacer a distancia?","options":["Las reuniones con clientes de los martes y jueves","La validaci\xf3n presencial de documentos","Los informes y la negociaci\xf3n interna","Las visitas de inspecci\xf3n en planta"],"answer":"Los informes y la negociaci\xf3n interna","answerIndex":2},{"question":"\xbfQu\xe9 paso falta antes de formalizar el acuerdo?","options":["Cerrar la oficina durante dos meses","Obtener la confirmaci\xf3n de recursos humanos","Renegociar el salario de Paula","Cambiar al director del \xe1rea"],"answer":"Obtener la confirmaci\xf3n de recursos humanos","answerIndex":1}]},{"id":4,"topic":"Patrocinio con condiciones de exclusividad","dialog":[{"speaker":"Ana","spanish":"En cuanto a la feria cultural, quisiera comentar la propuesta de patrocinio que recibimos esta ma\xf1ana, porque incluye visibilidad adicional a cambio de exclusividad.","english":"Regarding the cultural fair, I would like to discuss the sponsorship proposal we received this morning, because it includes additional visibility in exchange for exclusivity."},{"speaker":"Iv\xe1n","spanish":"El valor a\xf1adido es interesante; sin embargo, ceder la exclusividad total limitar\xeda la presencia de aliados con los que hemos trabajado durante a\xf1os.","english":"The added value is interesting; however, granting full exclusivity would limit the presence of partners we have worked with for years."},{"speaker":"Ana","spanish":"Estoy de acuerdo. Por un lado, el patrocinador principal cubrir\xeda buena parte del presupuesto; por otro lado, podr\xedamos perder relaciones estrat\xe9gicas que tardaron mucho en consolidarse.","english":"I agree. On the one hand, the main sponsor would cover a large part of the budget; on the other hand, we could lose strategic relationships that took a long time to build."},{"speaker":"Iv\xe1n","spanish":"\xbfQu\xe9 le parece si ofrecemos exclusividad solo en la inauguraci\xf3n y reservamos el resto del programa para colaboraciones complementarias?","english":"What do you think if we offer exclusivity only for the opening ceremony and reserve the rest of the program for complementary collaborations?"},{"speaker":"Ana","spanish":"Ese punto medio me convence, siempre que el calendario propuesto detalle los espacios de marca y evite conflictos con los compromisos ya asumidos.","english":"That middle ground works for me, provided the proposed timeline details the branding spaces and avoids conflicts with commitments already made."},{"speaker":"Iv\xe1n","spanish":"Entonces preparar\xe9 una contrapropuesta formal y, con cortes\xeda pero con firmeza, les explicar\xe9 que buscamos un acuerdo sostenible, no una concesi\xf3n total.","english":"Then I will prepare a formal counterproposal and, politely but firmly, explain that we are looking for a sustainable agreement, not a total concession."}],"questions":[{"question":"\xbfPor qu\xe9 dudan Ana e Iv\xe1n en aceptar la exclusividad total?","options":["Porque el patrocinador no ofrece visibilidad suficiente","Porque podr\xeda perjudicar relaciones estrat\xe9gicas ya construidas","Porque la feria se cancelar\xe1 este a\xf1o","Porque el presupuesto ya est\xe1 completamente cubierto"],"answer":"Porque podr\xeda perjudicar relaciones estrat\xe9gicas ya construidas","answerIndex":1},{"question":"\xbfQu\xe9 compromiso propone Iv\xe1n para acercarse a un acuerdo?","options":["Ofrecer exclusividad solo durante la inauguraci\xf3n","Eliminar toda presencia de marca del evento","Aceptar la propuesta sin cambios","Cambiar la fecha de la feria cultural"],"answer":"Ofrecer exclusividad solo durante la inauguraci\xf3n","answerIndex":0},{"question":"\xbfCon qu\xe9 tono piensa responder Iv\xe1n al patrocinador?","options":["Con iron\xeda y distancia","Con rapidez, pero sin revisar detalles","Con cortes\xeda, pero con firmeza","Con un mensaje informal y breve"],"answer":"Con cortes\xeda, pero con firmeza","answerIndex":2}]}],"stories":[{"id":1,"title":"El correo que evit\xf3 el conflicto","sentences":[{"spanish":"M\xf3nica recibi\xf3 un mensaje brusco de un proveedor que exig\xeda una respuesta inmediata sobre unos t\xe9rminos que a\xfan no hab\xedan sido revisados.","english":"M\xf3nica received a blunt message from a supplier demanding an immediate response about terms that had not yet been reviewed."},{"spanish":"En lugar de responder con el mismo tono, redact\xf3 un correo que empezaba con un saludo formal y resum\xeda con precisi\xf3n lo acordado hasta ese momento.","english":"Instead of replying in the same tone, she drafted an email that began with a formal greeting and precisely summarized what had been agreed up to that point."},{"spanish":"Despu\xe9s explic\xf3 que el retraso obedec\xeda a motivos operativos y propuso una reuni\xf3n de seguimiento para revisar la cl\xe1usula adicional que generaba dudas.","english":"She then explained that the delay was due to operational reasons and proposed a follow-up meeting to review the additional clause that was raising concerns."},{"spanish":"Tambi\xe9n dej\xf3 constancia de que su equipo estaba dispuesto a avanzar, siempre que el calendario revisado permitiera una evaluaci\xf3n responsable.","english":"She also placed on record that her team was willing to move forward, provided the revised timeline allowed for a responsible review."},{"spanish":"A la ma\xf1ana siguiente, el proveedor contest\xf3 con un tono mucho m\xe1s colaborativo y acept\xf3 revisar la contrapropuesta antes de insistir en una decisi\xf3n final.","english":"The next morning, the supplier replied in a much more cooperative tone and agreed to review the counterproposal before insisting on a final decision."}]},{"id":2,"title":"La reuni\xf3n en la que todos cedieron un poco","sentences":[{"spanish":"El comit\xe9 lleg\xf3 a la sala con posiciones muy distintas sobre el presupuesto, y parec\xeda imposible alcanzar un acuerdo en menos de una hora.","english":"The committee arrived with very different positions on the budget, and it seemed impossible to reach an agreement in less than an hour."},{"spanish":"Sin embargo, la directora pidi\xf3 que cada parte explicara no solo su petici\xf3n, sino tambi\xe9n el margen de maniobra que estaba dispuesta a reconocer.","english":"However, the director asked each side to explain not only its request, but also the room for maneuver it was willing to acknowledge."},{"spanish":"Esa pregunta cambi\xf3 el tono, porque quienes defend\xedan m\xe1s inversi\xf3n admitieron que pod\xedan escalonar ciertas compras, y quienes exig\xedan recortes aceptaron proteger la formaci\xf3n del personal.","english":"That question changed the tone, because those arguing for more investment admitted they could phase certain purchases, and those demanding cuts agreed to protect staff training."},{"spanish":"En resumen, nadie obtuvo todo lo que quer\xeda, pero cada grupo vio reflejada al menos una prioridad estrat\xe9gica en la decisi\xf3n consensuada.","english":"In summary, nobody got everything they wanted, but each group saw at least one strategic priority reflected in the consensus decision."},{"spanish":"Al salir, varios participantes comentaron que la negociaci\xf3n hab\xeda sido exigente precisamente porque se hab\xeda hecho con respeto y claridad.","english":"As they left, several participants remarked that the negotiation had been demanding precisely because it had been carried out with respect and clarity."}]},{"id":3,"title":"Una pr\xf3rroga bien negociada","sentences":[{"spanish":"Sergio sab\xeda que solicitar una pr\xf3rroga para la auditor\xeda pod\xeda interpretarse como una se\xf1al de desorden, as\xed que prepar\xf3 la petici\xf3n con mucho cuidado.","english":"Sergio knew that requesting an extension for the audit could be interpreted as a sign of disorganization, so he prepared the request very carefully."},{"spanish":"Primero reuni\xf3 pruebas de que el retraso se deb\xeda a cambios regulatorios de \xfaltima hora y no a una falta de seguimiento interno.","english":"First he gathered evidence that the delay was due to last-minute regulatory changes and not to a lack of internal follow-up."},{"spanish":"Luego propuso un calendario alternativo en el que cada entrega parcial quedaba asociada a una revisi\xf3n concreta por parte del cliente.","english":"Then he proposed an alternative timeline in which each partial delivery was linked to a specific client review."},{"spanish":"Cuando present\xf3 la idea, dej\xf3 claro que su equipo asumir\xeda la responsabilidad de enviar avances semanales para reducir la incertidumbre.","english":"When he presented the idea, he made it clear that his team would take responsibility for sending weekly updates to reduce uncertainty."},{"spanish":"Gracias a ese enfoque, la otra parte acept\xf3 la pr\xf3rroga y destac\xf3 que la propuesta provisional transmit\xeda seriedad en lugar de improvisaci\xf3n.","english":"Thanks to that approach, the other party accepted the extension and noted that the provisional proposal conveyed seriousness rather than improvisation."}]}],"speaking":{"title":"Negociar y comunicar con registro formal","description":"Practica reuniones, compromisos, correos profesionales y lenguaje diplom\xe1tico.","questions_and_answers":[{"question":{"spanish":"Pide una pr\xf3rroga de forma profesional.","english":"Request an extension in a professional way."},"answer":{"spanish":"Le escribo para solicitar una pr\xf3rroga breve, ya que necesitamos verificar unos datos cr\xedticos antes de enviar la versi\xf3n final.","english":"I am writing to request a short extension, since we need to verify some critical data before sending the final version."}},{"question":{"spanish":"Prop\xf3n un punto medio en una negociaci\xf3n.","english":"Propose a middle ground in a negotiation."},"answer":{"spanish":"Propongo que adoptemos una soluci\xf3n escalonada, de modo que ambas partes cedan en algo sin comprometer los objetivos principales.","english":"I propose that we adopt a phased solution so that both parties give ground on something without compromising the main objectives."}},{"question":{"spanish":"Abre un correo formal sobre un presupuesto.","english":"Open a formal email about a budget."},"answer":{"spanish":"Estimado se\xf1or Ram\xedrez: Le escribo para revisar los t\xe9rminos del presupuesto adjunto y aclarar algunos supuestos de coste.","english":"Dear Mr. Ram\xedrez: I am writing to review the terms of the attached budget and clarify some cost assumptions."}},{"question":{"spanish":"Resume una reuni\xf3n de seguimiento.","english":"Summarize a follow-up meeting."},"answer":{"spanish":"En resumen, acordamos mantener el calendario propuesto con dos ajustes menores y dejar constancia de las tareas asignadas a cada equipo.","english":"In summary, we agreed to keep the proposed timeline with two minor adjustments and to place on record the tasks assigned to each team."}},{"question":{"spanish":"Explica por qu\xe9 un plazo no es viable.","english":"Explain why a deadline is not feasible."},"answer":{"spanish":"El plazo actual no es viable porque la carga de trabajo ha aumentado y una entrega precipitada pondr\xeda en riesgo la calidad del proyecto.","english":"The current deadline is not feasible because the workload has increased and a rushed delivery would put the quality of the project at risk."}},{"question":{"spanish":"Pide m\xe1s detalles con cortes\xeda.","english":"Ask for more details politely."},"answer":{"spanish":"\xbfQu\xe9 le parece si nos comparte una versi\xf3n m\xe1s detallada del alcance para que podamos evaluar la propuesta con el debido rigor?","english":"What do you think of sharing a more detailed version of the scope so that we can evaluate the proposal with due rigor?"}},{"question":{"spanish":"Exp\xf3n el valor a\xf1adido de una propuesta.","english":"Explain the added value of a proposal."},"answer":{"spanish":"El valor a\xf1adido de esta propuesta reside en que reduce tiempos de respuesta sin exigir una inversi\xf3n completa desde el primer mes.","english":"The added value of this proposal lies in the fact that it reduces response times without requiring a full investment from the first month."}},{"question":{"spanish":"Di que est\xe1s dispuesto a negociar ciertas condiciones.","english":"Say that you are willing to negotiate certain terms."},"answer":{"spanish":"Estamos dispuestos a negociar ciertas condiciones, siempre que el alcance t\xe9cnico y los criterios de calidad queden claramente definidos.","english":"We are willing to negotiate certain terms, provided the technical scope and quality criteria are clearly defined."}},{"question":{"spanish":"Formula una contrapropuesta clara.","english":"Formulate a clear counterproposal."},"answer":{"spanish":"Nuestra contrapropuesta consiste en mantener el precio base y ampliar el soporte solo durante la fase de implementaci\xf3n inicial.","english":"Our counterproposal is to keep the base price and expand support only during the initial implementation phase."}},{"question":{"spanish":"Aclara un desacuerdo sin sonar agresivo.","english":"Clarify a disagreement without sounding aggressive."},"answer":{"spanish":"Con el debido respeto, consideramos que esa estimaci\xf3n no refleja la complejidad real del trabajo ni el tiempo de revisi\xf3n necesario.","english":"With due respect, we believe that estimate does not reflect the real complexity of the work or the review time required."}},{"question":{"spanish":"Solicita confirmaci\xf3n despu\xe9s de un acuerdo verbal.","english":"Request confirmation after a verbal agreement."},"answer":{"spanish":"Seg\xfan lo acordado en la llamada, agradecer\xeda que nos confirmara por escrito los hitos y el calendario revisado.","english":"As agreed on the call, I would appreciate it if you could confirm the milestones and revised timeline in writing."}},{"question":{"spanish":"Explica c\xf3mo repartir\xedas la carga de trabajo.","english":"Explain how you would distribute the workload."},"answer":{"spanish":"Propongo redistribuir la carga de trabajo entre dos equipos, de modo que la revisi\xf3n t\xe9cnica avance en paralelo con la documentaci\xf3n.","english":"I propose redistributing the workload between two teams so that the technical review can proceed in parallel with the documentation."}},{"question":{"spanish":"Pide una reuni\xf3n presencial cuando sea necesaria.","english":"Request an in-person meeting when necessary."},"answer":{"spanish":"Dado que quedan varios puntos sensibles por cerrar, considero conveniente convocar una reuni\xf3n presencial antes de tomar la decisi\xf3n final.","english":"Given that several sensitive points remain unresolved, I believe it would be advisable to call an in-person meeting before making the final decision."}},{"question":{"spanish":"Explica por qu\xe9 una soluci\xf3n escalonada puede ayudar.","english":"Explain why a phased solution can help."},"answer":{"spanish":"Una soluci\xf3n escalonada puede ayudar porque reduce el riesgo inicial y permite ajustar el proyecto a medida que se confirman los resultados.","english":"A phased solution can help because it reduces the initial risk and allows the project to be adjusted as results are confirmed."}},{"question":{"spanish":"Cierra un correo formal correctamente.","english":"Close a formal email properly."},"answer":{"spanish":"Quedo a la espera de su respuesta. Atentamente, Laura M\xe9ndez.","english":"I look forward to your reply. Sincerely, Laura M\xe9ndez."}},{"question":{"spanish":"Explica una prioridad estrat\xe9gica en una reuni\xf3n.","english":"Explain a strategic priority in a meeting."},"answer":{"spanish":"Nuestra prioridad estrat\xe9gica es consolidar el servicio actual antes de asumir nuevas l\xedneas de trabajo que puedan dispersar recursos.","english":"Our strategic priority is to consolidate the current service before taking on new lines of work that could spread resources too thin."}},{"question":{"spanish":"Pide que algo quede por escrito.","english":"Ask for something to be put in writing."},"answer":{"spanish":"Para evitar malentendidos, agradecer\xeda que dej\xe1ramos constancia por escrito de los cambios aprobados y de sus fechas de aplicaci\xf3n.","english":"To avoid misunderstandings, I would appreciate it if we placed the approved changes and their implementation dates in writing."}},{"question":{"spanish":"Exp\xf3n una reserva sobre una propuesta provisional.","english":"Express a reservation about a provisional proposal."},"answer":{"spanish":"La propuesta provisional resulta interesante, pero me preocupa que no especifique qui\xe9n asumir\xe1 la responsabilidad de las incidencias posteriores.","english":"The provisional proposal is interesting, but I am concerned that it does not specify who will take responsibility for later issues."}},{"question":{"spanish":"Sugiere una forma diplom\xe1tica de ceder en algo.","english":"Suggest a diplomatic way to give ground on something."},"answer":{"spanish":"Podr\xedamos ceder en el calendario inicial si, a cambio, se mantienen los est\xe1ndares de soporte y la cl\xe1usula de revisi\xf3n trimestral.","english":"We could give ground on the initial timeline if, in return, the support standards and quarterly review clause are maintained."}},{"question":{"spanish":"Explica c\xf3mo llegar\xedas a un acuerdo sostenible.","english":"Explain how you would reach a sustainable agreement."},"answer":{"spanish":"Llegar\xeda a un acuerdo sostenible identificando primero los puntos no negociables y buscando despu\xe9s un margen real para compromisos graduales.","english":"I would reach a sustainable agreement by first identifying the non-negotiable points and then looking for real room for gradual compromises."}}]}}}')}}]);